import { InjectionToken, Provider } from "@angular/core";
import { NgxIconExtension } from "./ngx-dropzone.models";

export const NgxIconImages = new InjectionToken<NgxIconExtension[]>("");

export function provideNgxIconImages(config: NgxIconExtension[]): Provider {
  return {
    provide: NgxIconImages,
    useValue: config,
  };
}

